def parse_monto(raw):
    t = str(raw).strip().replace(',', '.')
    try:
        n = float(t)
    except ValueError:
        raise ValueError(f"monto no numérico: {raw!r}") from None
    if n < 0:
        raise ValueError(f"monto negativo: {raw!r}")
    return n

